        var authValue = authHeader.ToString();
        if (string.IsNullOrWhiteSpace(authValue) || !authValue.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
        {
            log.LogWarning($"[{correlationId}] Invalid Authorization header format");
            return null;
