    private static void LogSafeSqlException(SqlException ex, ILogger log, string correlationId)
    {
        var safeMessage = ex.Message;
        
        foreach (var field in SensitiveFields)
        {
            safeMessage = System.Text.RegularExpressions.Regex.Replace(
                safeMessage, 
                $@"{field}\s*[=:]\s*[^\s,;]+", 
                $"{field}=[REDACTED]", 
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        }

        log.LogError($"[{correlationId}] SQL Exception occurred");
        log.LogError($"[{correlationId}] Error Number: {ex.Number}");
        log.LogError($"[{correlationId}] Error Message: {safeMessage}");
        log.LogError($"[{correlationId}] Procedure: {ex.Procedure ?? "[none]"}");
        log.LogError($"[{correlationId}] Line Number: {ex.LineNumber}");
        log.LogError($"[{correlationId}] Stack Trace: {SanitizeStackTrace(ex.StackTrace)}");
    }

    private static void LogSafeException(Exception ex, ILogger log, string correlationId)
