        log.LogError($"[{correlationId}] Exception Message: {RedactSensitiveData(ex.Message)}");
        log.LogError($"[{correlationId}] Stack Trace: {SanitizeStackTrace(ex.StackTrace)}");

        if (ex.InnerException != null)
        {
            log.LogError($"[{correlationId}] Inner Exception Type: {ex.InnerException.GetType().Name}");
            log.LogError($"[{correlationId}] Inner Exception Message: {RedactSensitiveData(ex.InnerException.Message)}");
        }
    }

    private static string RedactSensitiveData(string input)
    {
        if (string.IsNullOrEmpty(input))
            return input;

        var result = input;

        foreach (var field in SensitiveFields)
        {
            result = System.Text.RegularExpressions.Regex.Replace(
                result,
                $@"(""{field}""\s*:\s*""[^""]*"")|({field}\s*[=:]\s*[^\s,;}}]+)",
                $@"""{field}"":""[REDACTED]""",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        }

        result = System.Text.RegularExpressions.Regex.Replace(
            result,
            @"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b",
            match => MaskEmail(match.Value));

        result = System.Text.RegularExpressions.Regex.Replace(
            result,
            @"\b\d{3}-\d{2}-\d{4}\b",
            "[SSN-REDACTED]");

        result = System.Text.RegularExpressions.Regex.Replace(
            result,
            @"\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b",
            "[CARD-REDACTED]");

        return result;
    }

    private static string MaskSensitiveData(string value)
    {
        if (string.IsNullOrEmpty(value) || value.Length <= 4)
            return "****";

        return value.Substring(0, 2) + new string('*', value.Length - 4) + value.Substring(value.Length - 2);
    }

    private static string MaskEmail(string email)
    {
        if (string.IsNullOrEmpty(email) || !email.Contains("@"))
            return "[REDACTED]";

        var parts = email.Split('@');
        var localPart = parts[0];
        var domain = parts[1];

        var maskedLocal = localPart.Length > 2 
            ? localPart.Substring(0, 1) + "***" + localPart.Substring(localPart.Length - 1)
            : "***";

        return $"{maskedLocal}@{domain}";
    }

    private static string MaskQueryString(string queryString)
    {
        if (string.IsNullOrEmpty(queryString))
            return string.Empty;

        var result = queryString;
        
        foreach (var field in SensitiveFields)
        {
            result = System.Text.RegularExpressions.Regex.Replace(
                result,
                $@"{field}=[^&]*",
                $"{field}=[REDACTED]",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        }

        return result;
    }

    private static string SanitizeStackTrace(string stackTrace)
    {
        if (string.IsNullOrEmpty(stackTrace))
            return "[no stack trace]";

        var lines = stackTrace.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
        var sanitizedLines = lines.Select(line => RedactSensitiveData(line));
        
        return string.Join(Environment.NewLine, sanitizedLines);
    }
